const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'event_queue';

async function connectAndConsume() {
    try {
        const connection = await amqp.connect(RABBITMQ_URL);
        const channel = await connection.createChannel();

        await channel.assertQueue(QUEUE_NAME, {
            durable: true // Ensure queue survives RabbitMQ restarts
        });

        console.log(`[*] Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

        // Prefetch 1 message at a time to ensure fair dispatch and processing
        channel.prefetch(1);

        channel.consume(QUEUE_NAME, async (msg) => {
            if (msg !== null) {
                console.log(`[x] Received raw message: ${msg.content.toString()}`);
                try {
                    await processMessage(channel, msg);
                    channel.ack(msg); // Acknowledge message if processed successfully
                } catch (error) {
                    console.error(`[x] Error processing message: ${error.message}`);
                    // Nack the message and re-queue it. For persistent errors, consider dead-lettering.
                    channel.nack(msg, false, true); // Nack and re-queue
                }
            }
        }, {
            noAck: false // Explicitly set to false, we will ack manually
        });

        connection.on('close', (err) => {
            if (err) {
                console.error('RabbitMQ connection closed with error:', err);
                // In a real application, implement robust re-connection logic here
                setTimeout(connectAndConsume, 5000); // Attempt to reconnect after 5 seconds
            }
        });

        connection.on('error', (err) => {
            console.error('RabbitMQ connection error:', err);
        });

    } catch (error) {
        console.error('Failed to connect to RabbitMQ or start consumer:', error.message);
        setTimeout(connectAndConsume, 5000); // Attempt to reconnect after 5 seconds
    }
}

